sealed class DeepLinkRoute {
    data class Profile(val userId: String) : DeepLinkRoute()
    data class PaymentConfirm(val transactionId: String? = null) : DeepLinkRoute()
    data class ProductDetail(val productId: String) : DeepLinkRoute()
