// --- Validation Utilities ---

object DeepLinkValidator {

    private const val TAG = "DeepLinkValidator"
    private const val ALLOWED_SCHEME = "myapp"
    private const val MAX_PARAM_LENGTH = 128
    private const val MAX_URI_LENGTH = 2048

    // Strict pattern for numeric IDs only
    private val NUMERIC_ID_PATTERN = Pattern.compile("^[0-9]{1,20}$")

    // Strict pattern for alphanumeric IDs (e.g., transaction IDs)
    private val ALPHANUMERIC_ID_PATTERN = Pattern.compile("^[a-zA-Z0-9_-]{1,64}$")

    // Allowlisted routes with their security levels
    private val ALLOWLISTED_ROUTES: List<AllowlistedRoute> = listOf(
        AllowlistedRoute(
            hostPattern = "profile",
            pathPattern = Pattern.compile("^/([0-9]{1,20})$"),
            securityLevel = RouteSecurityLevel.AUTHENTICATED,
            description = "User profile view"
        ),
        AllowlistedRoute(
            hostPattern = "payment",
            pathPattern = Pattern.compile("^/confirm(?:\\?.*)?$"),
            securityLevel = RouteSecurityLevel.PRIVILEGED,
            description = "Payment confirmation"
        ),
        AllowlistedRoute(
            hostPattern = "product",
            pathPattern = Pattern.compile("^/([0-9]{1,20})$"),
            securityLevel = RouteSecurityLevel.PUBLIC,
            description = "Product detail view"
        ),
        AllowlistedRoute(
            hostPattern = "home",
            pathPattern = Pattern.compile("^/?$"),
            securityLevel = RouteSecurityLevel.PUBLIC,
            description = "Home screen"
        )
    )

    /**
     * Validates the URI scheme is our expected custom scheme.
     */
    fun isValidScheme(uri: Uri): Boolean {
        return uri.scheme?.lowercase() == ALLOWED_SCHEME
    }

    /**
     * Validates overall URI structure and length.
     */
    fun isValidUriStructure(uri: Uri): Boolean {
        val uriString = uri.toString()
        if (uriString.length > MAX_URI_LENGTH) {
            Log.w(TAG, "URI exceeds maximum length: ${uriString.length}")
            return false
        }
        if (uri.host.isNullOrBlank()) {
            Log.w(TAG, "URI has no host")
            return false
        }
        return true
    }

    /**
     * Validates a numeric ID parameter.
     */
    fun isValidNumericId(id: String?): Boolean {
        if (id.isNullOrBlank()) return false
        if (id.length > MAX_PARAM_LENGTH) return false
        return NUMERIC_ID_PATTERN.matcher(id).matches()
    }

    /**
     * Validates an alphanumeric ID parameter.
     */
    fun isValidAlphanumericId(id: String?): Boolean {
        if (id.isNullOrBlank()) return false
        if (id.length > MAX_PARAM_LENGTH) return false
        return ALPHANUMERIC_ID_PATTERN.matcher(id).matches()
    }

    /**
     * Sanitizes a string parameter by removing potentially dangerous characters.
     */
    fun sanitizeParameter(param: String?): String? {
        if (param == null) return null
        // Remove any characters that aren't alphanumeric, hyphens, or underscores
        return param.replace(Regex("[^a-zA-Z0-9_-]"), "").take(MAX_PARAM_LENGTH)
    }

    /**
     * Finds the matching allowlisted route for the given URI.
     * Returns null if no allowlisted route matches.
     */
    fun findAllowlistedRoute(uri: Uri): AllowlistedRoute? {
        val host = uri.host?.lowercase() ?: return null
        val path = uri.path ?: ""
        val pathWithQuery = if (uri.query != null) "$path?${uri.query}" else path

        return ALLOWLISTED_ROUTES.find { route ->
            route.hostPattern == host &&
                    (route.pathPattern.matcher(path).matches() ||
                            route.pathPattern.matcher(pathWithQuery).matches())
        }
    }

    /**
     * Checks if a query parameter name is in the allowlist for the given host.
     */
    private val ALLOWED_QUERY_PARAMS: Map<String, Set<String>> = mapOf(
        "payment" to setOf("transaction_id", "ref"),
        "product" to setOf("source", "campaign"),
        "profile" to setOf("tab")
    )

    fun areQueryParamsAllowed(uri: Uri): Boolean {
        val host = uri.host?.lowercase() ?: return false
        val allowedParams = ALLOWED_QUERY_PARAMS[host] ?: emptySet()
        val actualParams = uri.queryParameterNames

        for (param in actualParams) {
            if (param !in allowedParams) {
                Log.w(TAG, "Disallowed query parameter '$param' for host '$host'")
                return false
            }
        }
        return true
    }
}

// --- Authorization Service ---

/**
 * Handles authorization checks for privileged routes.
 * In production, this would integrate with your auth system.
 */
interface AuthorizationService {
    fun isUserAuthenticated(): Boolean
    fun isUserAuthorizedForPayment(): Boolean
    fun getCurrentUserId(): String?
}

class DefaultAuthorizationService(private val context: Context) : AuthorizationService {

    override fun isUserAuthenticated(): Boolean {
        // In production: Check actual auth state from your auth manager
        val prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        val token = prefs.getString("auth_token", null)
        val expiry = prefs.getLong("token_expiry", 0)
        return !token.isNullOrBlank() && System.currentTimeMillis() < expiry
    }

    override fun isUserAuthorizedForPayment(): Boolean {
        // In production: Verify with server that user has payment permissions
        // This should ideally make a server-side check
        if (!isUserAuthenticated()) return false
        val prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        return prefs.getBoolean("payment_verified", false)
    }

    override fun getCurrentUserId(): String? {
        val prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        return prefs.getString("user_id", null)
    }
}

