/**
 * Parses and validates deep link URIs into typed route objects.
 * All parsing goes through the allowlist and validation pipeline.
 */
class DeepLinkParser(private val authService: AuthorizationService) {

    private val TAG = "DeepLinkParser"

    /**
     * Main entry point: Parse a URI into a validated DeepLinkRoute.
     */
    fun parse(uri: Uri): DeepLinkRoute {
        Log.d(TAG, "Parsing deep link: ${uri.toString().take(200)}")

        // Step 1: Validate scheme
        if (!DeepLinkValidator.isValidScheme(uri)) {
            Log.w(TAG, "Invalid scheme: ${uri.scheme}")
            return DeepLinkRoute.Invalid
        }

        // Step 2: Validate URI structure
        if (!DeepLinkValidator.isValidUriStructure(uri)) {
            Log.w(TAG, "Invalid URI structure")
            return DeepLinkRoute.Invalid
        }

        // Step 3: Check against allowlisted routes
        val allowlistedRoute = DeepLinkValidator.findAllowlistedRoute(uri)
        if (allowlistedRoute == null) {
            Log.w(TAG, "URI does not match any allowlisted route: host=${uri.host}, path=${uri.path}")
            return DeepLinkRoute.Invalid
        }

        // Step 4: Validate query parameters are allowed
        if (!DeepLinkValidator.areQueryParamsAllowed(uri)) {
            Log.w(TAG, "URI contains disallowed query parameters")
            return DeepLinkRoute.Invalid
        }

        // Step 5: Check authorization for the route's security level
        val authResult = checkAuthorization(allowlistedRoute, uri)
        if (authResult != null) {
            return authResult
        }

        // Step 6: Parse route-specific parameters with validation
        return parseRoute(uri, allowlistedRoute)
    }

    /**
     * Checks if the current user is authorized for the given route.
     * Returns an Unauthorized route if not authorized, null if authorized.
     */
    private fun checkAuthorization(route: AllowlistedRoute, uri: Uri): DeepLinkRoute? {
        return when (route.securityLevel) {
            RouteSecurityLevel.PUBLIC -> null // No auth needed

            RouteSecurityLevel.AUTHENTICATED -> {
                if (!authService.isUserAuthenticated()) {
                    Log.w(TAG, "Unauthenticated access attempt to: ${route.description}")
                    DeepLinkRoute.Unauthorized(
                        reason = "Authentication required",
                        attemptedRoute = uri.toString()
                    )
                } else null
            }

            RouteSecurityLevel.PRIVILEGED -> {
                if (!authService.isUserAuthenticated()) {
                    Log.w(TAG, "Unauthenticated access attempt to privileged route: ${route.description}")
                    DeepLinkRoute.Unauthorized(
                        reason = "Authentication required",
                        attemptedRoute = uri.toString()
                    )
                } else if (route.hostPattern == "payment" && !authService.isUserAuthorizedForPayment()) {
                    Log.w(TAG, "Unauthorized payment access attempt")
                    DeepLinkRoute.Unauthorized(
                        reason = "Payment authorization required",
                        attemptedRoute = uri.toString()
                    )
                } else null
            }
        }
    }

    /**
     * Parses route-specific parameters with strict validation.
     */
    private fun parseRoute(uri: Uri, allowlistedRoute: AllowlistedRoute): DeepLinkRoute {
        val host = uri.host?.lowercase() ?: return DeepLinkRoute.Invalid
        val pathSegments = uri.pathSegments

        return when (host) {
            "profile" -> parseProfileRoute(pathSegments)
            "payment" -> parsePaymentRoute(uri, pathSegments)
            "product" -> parseProductRoute(pathSegments)
            "home" -> DeepLinkRoute.Home
            else -> {
                Log.w(TAG, "Unhandled host after allowlist check: $host")
                DeepLinkRoute.Invalid
            }
        }
    }

    private fun parseProfileRoute(pathSegments: List<String>): DeepLinkRoute {
        if (pathSegments.size != 1) {
            Log.w(TAG, "Invalid profile path segments count: ${pathSegments.size}")
            return DeepLinkRoute.Invalid
        }

        val userId = pathSegments[0]

        // Validate user ID is a proper numeric ID
        if (!DeepLinkValidator.isValidNumericId(userId)) {
            Log.w(TAG, "Invalid profile user ID format")
            return DeepLinkRoute.Invalid
        }

        return DeepLinkRoute.Profile(userId = userId)
    }

    private fun parsePaymentRoute(uri: Uri, pathSegments: List<String>): DeepLinkRoute {
        if (pathSegments.size != 1 || pathSegments[0] != "confirm") {
            Log.w(TAG, "Invalid payment path")
            return DeepLinkRoute.Invalid
        }

        // Optional transaction_id query parameter
        val transactionId = uri.getQueryParameter("transaction_id")
        if (transactionId != null && !DeepLinkValidator.isValidAlphanumericId(transactionId)) {
            Log.w(TAG, "Invalid transaction ID format")
            return DeepLinkRoute.Invalid
        }

        return DeepLinkRoute.PaymentConfirm(
            transactionId = DeepLinkValidator.sanitizeParameter(transactionId)
        )
    }

    private fun parseProductRoute(pathSegments: List<String>): DeepLinkRoute {
        if (pathSegments.size != 1) {
            Log.w(TAG, "Invalid product path segments count: ${pathSegments.size}")
            return DeepLinkRoute.Invalid
        }

        val productId = pathSegments[0]

        if (!DeepLinkValidator.isValidNumericId(productId)) {
            Log.w(TAG, "Invalid product ID format")
            return DeepLinkRoute.Invalid
        }

        return DeepLinkRoute.ProductDetail(productId = productId)
    }
}

// --- Navigation Handler ---

/**
 * Handles navigation to the appropriate Activity based on the parsed route.
 */
class DeepLinkNavigator(private val context: Context) {

    private val TAG = "DeepLinkNavigator"

    /**
     * Navigate to the appropriate screen for the given route.
     * All routes have already been validated and authorized by the parser.
     */
    fun navigate(route: DeepLinkRoute) {
        Log.d(TAG, "Navigating to route: $route")

        when (route) {
            is DeepLinkRoute.Profile -> navigateToProfile(route.userId)
            is DeepLinkRoute.PaymentConfirm -> navigateToPaymentConfirm(route.transactionId)
            is DeepLinkRoute.ProductDetail -> navigateToProductDetail(route.productId)
            is DeepLinkRoute.Home -> navigateToHome()
            is DeepLinkRoute.Invalid -> navigateToHome() // Safe fallback
            is DeepLinkRoute.Unauthorized -> navigateToLogin(route.reason, route.attemptedRoute)
        }
    }

    private fun navigateToProfile(userId: String) {
        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToPaymentConfirm(transactionId: String?) {
        val intent = Intent(context, PaymentConfirmActivity::class.java).apply {
            transactionId?.let { putExtra(PaymentConfirmActivity.EXTRA_TRANSACTION_ID, it) }
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToProductDetail(productId: String) {
        val intent = Intent(context, ProductDetailActivity::class.java).apply {
            putExtra(ProductDetailActivity.EXTRA_PRODUCT_ID, productId)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToHome() {
        val intent = Intent(context, HomeActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToLogin(reason: String, attemptedRoute: String) {
        val intent = Intent(context, LoginActivity::class.java).apply {
            putExtra(LoginActivity.EXTRA_AUTH_REASON, reason)
            // Store the attempted route so we can redirect after login
            putExtra(LoginActivity.EXTRA_REDIRECT_URI, attemptedRoute)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }
}

// --- Deep Link Handler Activity ---

/**
 * Entry point Activity that receives deep links from the system.
 * Declared in AndroidManifest.xml with intent-filter for myapp:// scheme.
 *
 * AndroidManifest.xml should contain:
 * <activity
 *     android:name=".deeplink.DeepLinkHandlerActivity"
 *     android:exported="true"
 *     android:launchMode="singleTask">
 *     <intent-filter>
 *         <action android:name="android.intent.action.VIEW" />
 *         <category android:name="android.intent.category.DEFAULT" />
 *         <category android:name="android.intent.category.BROWSABLE" />
 *         <data android:scheme="myapp" />
 *     </intent-filter>
 * </activity>
 */
class DeepLinkHandlerActivity : Activity() {

    private val TAG = "DeepLinkHandler"

    private lateinit var parser: DeepLinkParser
    private lateinit var navigator: DeepLinkNavigator

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val authService = DefaultAuthorizationService(applicationContext)
        parser = DeepLinkParser(authService)
        navigator = DeepLinkNavigator(applicationContext)

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        intent?.let { handleIntent(it) }
    }

    private fun handleIntent(intent: Intent) {
        val uri = intent.data

        if (uri == null) {
            Log.w(TAG, "Deep link intent received with no data URI")
            navigateToHomeAndFinish()
            return
        }

        Log.d(TAG, "Received deep link: ${uri.toString().take(200)}")

        // Parse and validate the deep link
        val route = parser.parse(uri)

        // Log for analytics (sanitized)
        logDeepLinkEvent(route)

        // Navigate to the appropriate screen
        navigator.navigate(route)

        // Finish this transparent handler activity
        finish()
    }

    private fun navigateToHomeAndFinish() {
        navigator.navigate(DeepLinkRoute.Home)
        finish()
    }

    private fun logDeepLinkEvent(route: DeepLinkRoute) {
        // Log sanitized route info for analytics - never log raw URIs with parameters
        val routeName = when (route) {
            is DeepLinkRoute.Profile -> "profile"
            is DeepLinkRoute.PaymentConfirm -> "payment_confirm"
            is DeepLinkRoute.ProductDetail -> "product_detail"
            is DeepLinkRoute.Home -> "home"
            is DeepLinkRoute.Invalid -> "invalid"
            is DeepLinkRoute.Unauthorized -> "unauthorized"
        }
        Log.i(TAG, "Deep link routed to: $routeName")
    }
}

